DATA_DIR = 'data'


# Helper functions to read and write data

def read_pipe_delimited_file(filepath, num_fields=None):
    """
    Read a pipe-delimited file and return list of lists with stripped elements
    If num_fields is provided, ensures each row has that many fields (pads with empty strings if needed)
    """
    data = []
    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if num_fields:
                    if len(parts) < num_fields:
                        parts += [''] * (num_fields - len(parts))
                    elif len(parts) > num_fields:
                        parts = parts[:num_fields]
                parts = [p.strip() for p in parts]
                data.append(parts)
    except FileNotFoundError:
        pass
    return data


def write_pipe_delimited_file(filepath, list_of_lists):
    """
    Write a list of lists to a pipe-delimited file
    """
    try:
        with open(filepath, 'w', encoding='utf-8') as f:
            for row in list_of_lists:
                f.write('|'.join(row) + '\n')
    except Exception as e:
        print(f'Error writing file {filepath}: {e}')


# Data loading by file according to Section 3 with field order as is

